+            lines += 1;
+        }
+
+        // Spinner (bottom)
+        if self.show_spinner {
+            lines += 1;
+        }
+
+        // Status bar (bottom)
+        if self.show_status_bar {
+            lines += 1;
+        }
+
+        // Help (bottom)
+        if self.show_help {
+            lines += 1;
+        }
+
+        lines
     }

